SHOWS = SHOW_LIST;

const TMDB_KEY = "8265bd1679663a7ea12ac168da84d2e8";
const TMDB_IMG = "https://image.tmdb.org/t/p/w500";

function loadPostersCache(): Record<string, string> {
  try {
    return JSON.parse(localStorage.getItem(POSTERS_CACHE_KEY) || "{}");
  } catch {
    return {};
  }
}
function savePostersCache(c: Record<string, string>) {
  try {
    localStorage.setItem(POSTERS_CACHE_KEY, JSON.stringify(c));
  } catch {}
}

async function loadPosters(): Promise<void> {
  // Poster paths are baked into MOVIE_LIST and SHOW_LIST at build time, so we
  // just expand them to full image URLs here — no network calls, no rate limiting.
  const cache = loadPostersCache();
  for (const m of MOVIES) {
    if (m.poster && !m.poster.startsWith("http")) {
      m.poster = `${TMDB_IMG}${m.poster}`;
    } else if (!m.poster && cache[m.id]) {
      m.poster = `${TMDB_IMG}${cache[m.id]}`;
    }
  }
  for (const s of SHOWS) {
    if (s.poster && !s.poster.startsWith("http")) {
      s.poster = `${TMDB_IMG}${s.poster}`;
    }
  }
}

/* ----- TV show details: fetched on demand to populate the season picker ----- */
const SHOW_DETAILS_CACHE_KEY = "harriubg.shows.v1";
function loadShowDetailsCache(): Record<string, ShowDetails> {
  try {
    return JSON.parse(localStorage.getItem(SHOW_DETAILS_CACHE_KEY) || "{}");
  } catch {
    return {};
  }
}
function saveShowDetailsCache(c: Record<string, ShowDetails>) {
  try {
    localStorage.setItem(SHOW_DETAILS_CACHE_KEY, JSON.stringify(c));
  } catch {}
}
async function fetchShowDetails(showId: number): Promise<ShowDetails | null> {
  const cache = loadShowDetailsCache();
  const k = String(showId);
  if (cache[k]) return cache[k];
  try {
    const r = await fetch(
      `https://api.themoviedb.org/3/tv/${showId}?api_key=${TMDB_KEY}`,
    );
    if (!r.ok) return null;
    const d = await r.json();
    const seasons: ShowSeason[] = (d.seasons || [])
      .filter((s: any) => s.season_number > 0 && s.episode_count > 0)
      .map((s: any) => ({
        season_number: s.season_number,
        episode_count: s.episode_count,
        name: s.name || `Season ${s.season_number}`,
      }));
    if (seasons.length === 0) return null;
    const details: ShowDetails = { id: showId, seasons };
    cache[k] = details;
    saveShowDetailsCache(cache);
    return details;
  } catch {
    return null;
  }
}

/* ============================================================
   Embed URL builders (cineby uses similar providers under the hood)
   ============================================================ */

function buildEmbedUrl(movieId: number, server: string): string {
  switch (server) {
    case "vidsrc.cc":
      return `https://vidsrc.cc/v2/embed/movie/${movieId}`;
    case "vidsrc.xyz":
      return `https://vidsrc.xyz/embed/movie?tmdb=${movieId}`;
    case "embed.su":
      return `https://embed.su/embed/movie/${movieId}`;
    case "vidlink.pro":
      return `https://vidlink.pro/movie/${movieId}?primaryColor=22d3ee&secondaryColor=a78bfa&iconColor=ffffff&autoplay=false`;
    case "2embed.cc":
      return `https://www.2embed.cc/embed/${movieId}`;
    default:
      return `https://vidsrc.cc/v2/embed/movie/${movieId}`;
  }
}

function buildShowEmbedUrl(
  showId: number,
  season: number,
  episode: number,
  server: string,
): string {
  switch (server) {
    case "vidsrc.cc":
      return `https://vidsrc.cc/v2/embed/tv/${showId}/${season}/${episode}`;
    case "vidsrc.xyz":
      return `https://vidsrc.xyz/embed/tv?tmdb=${showId}&season=${season}&episode=${episode}`;
    case "embed.su":
      return `https://embed.su/embed/tv/${showId}/${season}/${episode}`;
    case "vidlink.pro":
      return `https://vidlink.pro/tv/${showId}/${season}/${episode}?primaryColor=22d3ee&secondaryColor=a78bfa&iconColor=ffffff&autoplay=false`;
    case "2embed.cc":
      return `https://www.2embed.cc/embedtv/${showId}&s=${season}&e=${episode}`;
    default:
      return `https://vidsrc.cc/v2/embed/tv/${showId}/${season}/${episode}`;
  }
}

/* ----- blob-URL cloaking ----------
   Wrapping the real iframe inside a blob URL hides the source URL from
   network-level filters that scan page HTML. The iframe's src appears as
   `blob:...` instead of revealing the game / streaming provider. */

const activeBlobs = new Set<string>();

function revokeBlobs() {
  activeBlobs.forEach((u) => URL.revokeObjectURL(u));
  activeBlobs.clear();
}

function makeBlobUrl(html: string): string {
  const blob = new Blob([html], { type: "text/html" });
  const url = URL.createObjectURL(blob);
  activeBlobs.add(url);
  return url;
}

/** Wrap a third-party URL in a tiny blob page so the iframe src is `blob:...`. */
function cloakUrl(url: string, title: string): string {
  const safeUrl = url.replace(/"/g, "&quot;");
  const safeTitle = escapeHtml(title);
  const html = `<!doctype html><html><head><meta charset="utf-8"><title>${safeTitle}</title>
<style>html,body,iframe{margin:0;padding:0;width:100%;height:100%;border:0;background:#000;overflow:hidden}</style>
</head><body>
<iframe src="${safeUrl}" allow="autoplay; fullscreen; encrypted-media; picture-in-picture; clipboard-write; gamepad" allowfullscreen referrerpolicy="no-referrer"></iframe>
</body></html>`;
  return makeBlobUrl(html);
}

/** Fetch a game's HTML, normalize its <base href>, and serve via blob URL. */
async function cloakGameHtml(g: Game): Promise<string> {
  try {
    const res = await fetch(g.url, { cache: "force-cache" });
    if (!res.ok) throw new Error(`fetch ${g.url} -> ${res.status}`);
    let html = await res.text();
    // For multi-file games hosted on harriwalk0/assets, the embedded base href
    // points at a 403'd fork — rewrite it to the working CDN.
    if (g.multiFile) {
      const goodBase = `${HARRI_BASE}/${g.id}/`;
      if (/<base\s[^>]*href=/i.test(html)) {
        html = html.replace(
          /<base\s[^>]*href=["'][^"']*["'][^>]*>/i,
          `<base href="${goodBase}">`,
        );
      } else {
        html = html.replace(
          /<head([^>]*)>/i,
          `<head$1><base href="${goodBase}">`,
        );
      }
    }
    // Single-file games already have a working <base href> baked in (e.g.
    // bubbls/youtube-playables, freebuisness/assets, etc).
    html = html.replace(
      /<title>[\s\S]*?<\/title>/i,
      `<title>${escapeHtml(g.name)}</title>`,
    );
    return makeBlobUrl(html);
  } catch (err) {
    console.error(err);
    return cloakUrl(g.url, g.name);
  }
}

