/* ============================================================
   Constellation background — always on, sensible defaults
   ============================================================ */

type Star = { x: number; y: number; vx: number; vy: number; r: number };

const STAR_DENSITY = 160;
const STAR_SPEED = 1.0; // multiplier
const LINK_DIST = 130;

let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;
let stars: Star[] = [];
let rafId = 0;

function rebuildStars() {
  if (!canvas) return;
  const dpr = Math.min(window.devicePixelRatio || 1, 2);
  const w = window.innerWidth;
  const h = window.innerHeight;
  canvas.width = w * dpr;
  canvas.height = h * dpr;
  canvas.style.width = w + "px";
  canvas.style.height = h + "px";
  ctx?.setTransform(dpr, 0, 0, dpr, 0, 0);

  stars = new Array(STAR_DENSITY).fill(0).map(() => ({
    x: Math.random() * w,
    y: Math.random() * h,
    vx: (Math.random() - 0.5) * 0.6,
    vy: (Math.random() - 0.5) * 0.6,
    r: Math.random() * 1.4 + 0.4,
  }));
}

function tick() {
  if (!ctx || !canvas) return;
  const w = window.innerWidth;
  const h = window.innerHeight;
  ctx.clearRect(0, 0, w, h);

  const starColor = getCssVar("--star") || "200, 220, 255";

  for (const s of stars) {
    s.x += s.vx * STAR_SPEED;
    s.y += s.vy * STAR_SPEED;
    if (s.x < 0) s.x += w;
    if (s.x > w) s.x -= w;
    if (s.y < 0) s.y += h;
    if (s.y > h) s.y -= h;

    ctx.beginPath();
    ctx.fillStyle = `rgba(${starColor}, ${0.55 + s.r * 0.25})`;
    ctx.shadowBlur = 6;
    ctx.shadowColor = `rgba(${starColor}, 0.6)`;
    ctx.arc(s.x, s.y, s.r, 0, Math.PI * 2);
    ctx.fill();
  }
  ctx.shadowBlur = 0;

  for (let i = 0; i < stars.length; i++) {
    for (let j = i + 1; j < stars.length; j++) {
      const a = stars[i],
        b = stars[j];
      const dx = a.x - b.x;
      const dy = a.y - b.y;
      const d = Math.sqrt(dx * dx + dy * dy);
      if (d < LINK_DIST) {
        const alpha = (1 - d / LINK_DIST) * 0.18;
        ctx.beginPath();
        ctx.strokeStyle = `rgba(${starColor}, ${alpha})`;
        ctx.lineWidth = 0.6;
        ctx.moveTo(a.x, a.y);
        ctx.lineTo(b.x, b.y);
        ctx.stroke();
      }
    }
  }
  rafId = requestAnimationFrame(tick);
}

function getCssVar(name: string): string {
  return getComputedStyle(document.documentElement)
    .getPropertyValue(name)
    .trim();
}

function initConstellation() {
  canvas = document.getElementById("constellation") as HTMLCanvasElement;
  if (!canvas) return;
  ctx = canvas.getContext("2d");
  rebuildStars();
  cancelAnimationFrame(rafId);
  rafId = requestAnimationFrame(tick);

  window.addEventListener("resize", rebuildStars);
}

/* ============================================================
   Tabs
   ============================================================ */

function setTab(tab: Tab) {
  document.querySelectorAll<HTMLButtonElement>(".tab").forEach((btn) => {
    btn.classList.toggle("active", btn.dataset.tab === tab);
  });
  document.querySelectorAll<HTMLElement>(".view").forEach((v) => {
    v.classList.toggle("active", v.id === `view-${tab}`);
  });
  window.scrollTo({ top: 0, behavior: "smooth" });
  history.replaceState(null, "", `#${tab}`);
}

function initTabs() {
  document.querySelectorAll<HTMLButtonElement>("[data-tab]").forEach((btn) => {
    btn.addEventListener("click", (e) => {
      e.preventDefault();
      setTab(btn.dataset.tab as Tab);
    });
  });
  document.querySelectorAll<HTMLButtonElement>("[data-go]").forEach((btn) => {
    btn.addEventListener("click", () => setTab(btn.dataset.go as Tab));
  });

  const initial = (location.hash.replace("#", "") || "home") as Tab;
  if (["home", "games", "movies", "shows", "settings"].includes(initial))
    setTab(initial);
}

/* ============================================================
   Card rendering — cover image with gradient fallback on error
   ============================================================ */

function gradientFor(seed: string): string {
  let h = 0;
  for (let i = 0; i < seed.length; i++) h = (h * 31 + seed.charCodeAt(i)) >>> 0;
  const hue1 = h % 360;
  const hue2 = (hue1 + 60 + ((h >> 8) % 80)) % 360;
  return `linear-gradient(135deg, hsl(${hue1} 70% 55%), hsl(${hue2} 75% 45%))`;
}

function buildCard(opts: {
  title: string;
  sub: string;
  cover?: string;
  onClick: () => void;
}): HTMLElement {
  const tile = document.createElement("button");
  tile.className = "card-tile";
  tile.type = "button";

  const grad = gradientFor(opts.title);
  const safeTitle = escapeHtml(opts.title);
  const safeSub = escapeHtml(opts.sub);

  if (opts.cover) {
    tile.innerHTML = `
      <div class="card-cover" data-fallback="${escapeAttr(grad)}" data-name="${safeTitle}">
        <img src="${escapeAttr(opts.cover)}" alt="${safeTitle}" loading="lazy" />
      </div>
      <div class="play-overlay"><div class="play-icon">
        <svg viewBox="0 0 24 24" width="22" height="22" fill="currentColor"><path d="M8 5v14l11-7z"/></svg>
      </div></div>
      <div class="card-meta">
        <div class="card-title">${safeTitle}</div>
        <div class="card-sub">${safeSub}</div>
      </div>`;
    const img = tile.querySelector("img")!;
    const cover = tile.querySelector(".card-cover") as HTMLElement;
    img.addEventListener("error", () => {
      cover.classList.add("placeholder");
      cover.style.background = grad;
      cover.innerHTML = `<span>${safeTitle}</span>`;
    });
  } else {
    tile.innerHTML = `
      <div class="card-cover placeholder" style="background:${grad}"><span>${safeTitle}</span></div>
      <div class="play-overlay"><div class="play-icon">
        <svg viewBox="0 0 24 24" width="22" height="22" fill="currentColor"><path d="M8 5v14l11-7z"/></svg>
      </div></div>
      <div class="card-meta">
        <div class="card-title">${safeTitle}</div>
        <div class="card-sub">${safeSub}</div>
      </div>`;
  }
  tile.addEventListener("click", opts.onClick);
  return tile;
}

function gameCard(g: Game): HTMLElement {
  return buildCard({
    title: g.name,
    sub: g.author || "Unknown studio",
    cover: g.cover,
    onClick: () => openGame(g),
  });
}

function movieCard(m: Movie): HTMLElement {
  return buildCard({
    title: m.title,
    sub: `${m.year} · ${m.genre}`,
    cover: m.poster,
    onClick: () => openMovie(m),
  });
}

function showCard(s: Show): HTMLElement {
  return buildCard({
    title: s.title,
    sub: `${s.year} · ${s.genre}`,
    cover: s.poster,
    onClick: () => openShow(s),
  });
}

function escapeHtml(s: string): string {
  return s.replace(
    /[&<>"']/g,
    (c) =>
      ({
        "&": "&amp;",
        "<": "&lt;",
        ">": "&gt;",
        '"': "&quot;",
        "'": "&#39;",
      })[c]!,
  );
}
function escapeAttr(s: string): string {
  return escapeHtml(s).replace(/`/g, "&#96;");
}

/* ============================================================
   Page renderers
   ============================================================ */

function renderFeatured() {
  const fGames = document.getElementById("featured-games")!;
  const fMovies = document.getElementById("featured-movies")!;
  const fShows = document.getElementById("featured-shows");

  fGames.innerHTML = "";
  if (GAMES.length === 0) {
    for (let i = 0; i < 8; i++) {
      const sk = document.createElement("div");
      sk.className = "card-tile skeleton";
      sk.innerHTML = `<div class="card-cover"></div><div class="card-meta"><div class="card-title">&nbsp;</div><div class="card-sub">&nbsp;</div></div>`;
      fGames.appendChild(sk);
    }
  } else {
    pickRandom(GAMES, 12).forEach((g) => fGames.appendChild(gameCard(g)));
  }

  fMovies.innerHTML = "";
  pickRandom(MOVIES, 12).forEach((m) => fMovies.appendChild(movieCard(m)));

  if (fShows) {
    fShows.innerHTML = "";
    pickRandom(SHOWS, 12).forEach((s) => fShows.appendChild(showCard(s)));
  }
}

function pickRandom<T>(arr: T[], n: number): T[] {
  const a = arr.slice();
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a.slice(0, Math.min(n, a.length));
}

function renderGames(query = "") {
  const grid = document.getElementById("games-grid")!;
  const empty = document.getElementById("games-empty")!;
  grid.innerHTML = "";
  const q = query.trim().toLowerCase();

  if (GAMES.length === 0) {
    for (let i = 0; i < 24; i++) {
      const sk = document.createElement("div");
      sk.className = "card-tile skeleton";
      sk.innerHTML = `<div class="card-cover"></div><div class="card-meta"><div class="card-title">&nbsp;</div><div class="card-sub">&nbsp;</div></div>`;
      grid.appendChild(sk);
    }
    empty.hidden = true;
    return;
  }

  const filtered = q
    ? GAMES.filter((g) => g.name.toLowerCase().includes(q))
    : GAMES;

  empty.hidden = filtered.length > 0;
  filtered.forEach((g) => grid.appendChild(gameCard(g)));
}

function renderMovies(query = "") {
  const grid = document.getElementById("movies-grid")!;
  const empty = document.getElementById("movies-empty")!;
  grid.innerHTML = "";
  const q = query.trim().toLowerCase();
  const filtered = q
    ? MOVIES.filter((m) => m.title.toLowerCase().includes(q))
    : MOVIES;
  empty.hidden = filtered.length > 0;
  filtered.forEach((m) => grid.appendChild(movieCard(m)));
}

function renderShows(query = "") {
  const grid = document.getElementById("shows-grid")!;
  const empty = document.getElementById("shows-empty")!;
  grid.innerHTML = "";
  const q = query.trim().toLowerCase();
  const filtered = q
    ? SHOWS.filter((s) => s.title.toLowerCase().includes(q))
    : SHOWS;
  empty.hidden = filtered.length > 0;
  filtered.forEach((s) => grid.appendChild(showCard(s)));
}

function renderStats() {
  document.getElementById("stat-games")!.textContent =
    GAMES.length > 0 ? String(GAMES.length) : "…";
  document.getElementById("stat-movies")!.textContent = String(MOVIES.length);
  const sShows = document.getElementById("stat-shows");
  if (sShows) sShows.textContent = String(SHOWS.length);
}

/* ============================================================
   Modal player
   ============================================================ */

let activeMovie: Movie | null = null;
let activeShow: Show | null = null;
let activeShowSeason = 1;
let activeShowEpisode = 1;

function openModal() {
  const m = document.getElementById("modal")!;
  m.hidden = false;
  document.body.style.overflow = "hidden";
  setLoading(true);
}

function setLoading(on: boolean) {
  const overlay = document.getElementById("modal-loading")!;
  overlay.hidden = !on;
}

function closeModal() {
  const m = document.getElementById("modal")!;
  const f = document.getElementById("modal-frame") as HTMLIFrameElement;
  if (document.fullscreenElement) document.exitFullscreen().catch(() => {});
  f.src = "about:blank";
  m.hidden = true;
  document.body.style.overflow = "";
  activeMovie = null;
  activeShow = null;
  const sr = document.getElementById("server-row")!;
  sr.hidden = true;
  sr.innerHTML = "";
  const ep = document.getElementById("episode-row");
  if (ep) {
    ep.hidden = true;
    ep.innerHTML = "";
  }
  setLoading(false);
  setTimeout(revokeBlobs, 500);
}

async function openGame(g: Game) {
  document.getElementById("modal-kind")!.textContent = "Game";
  document.getElementById("modal-title")!.textContent = g.name;
  (document.getElementById("server-row") as HTMLElement).hidden = true;
  const ep = document.getElementById("episode-row");
  if (ep) {
    ep.hidden = true;
    ep.innerHTML = "";
  }
  activeMovie = null;
  activeShow = null;
  openModal();

  const f = document.getElementById("modal-frame") as HTMLIFrameElement;
  f.src = "about:blank";
  const blobUrl = await cloakGameHtml(g);

  if (settings.aboutBlank) {
    openInAboutBlank(blobUrl, g.name);
    closeModal();
    return;
  }

  f.onload = () => setLoading(false);
  f.src = blobUrl;
}

function openMovie(m: Movie) {
  activeMovie = m;
  activeShow = null;
  const ep = document.getElementById("episode-row");
  if (ep) {
    ep.hidden = true;
    ep.innerHTML = "";
  }
  document.getElementById("modal-kind")!.textContent = `Movie · ${m.year}`;
  document.getElementById("modal-title")!.textContent = m.title;

  const realUrl = buildEmbedUrl(m.id, settings.server);
  const blobUrl = cloakUrl(realUrl, m.title);

  if (settings.aboutBlank) {
    openInAboutBlank(blobUrl, m.title);
    return;
  }

  openModal();
  const f = document.getElementById("modal-frame") as HTMLIFrameElement;
  f.onload = () => setLoading(false);
  f.src = blobUrl;

  const sr = document.getElementById("server-row")!;
  sr.innerHTML = "";
  SERVERS.forEach((s) => {
    const b = document.createElement("button");
    b.className = "server-btn" + (s.id === settings.server ? " active" : "");
    b.textContent = s.label;
    b.addEventListener("click", () => {
      sr.querySelectorAll(".server-btn").forEach((el) =>
        el.classList.remove("active"),
      );
      b.classList.add("active");
      setLoading(true);
      const newUrl = buildEmbedUrl(m.id, s.id);
      f.src = cloakUrl(newUrl, m.title);
    });
    sr.appendChild(b);
  });
  sr.hidden = false;
}

async function openShow(sh: Show) {
  activeShow = sh;
  activeMovie = null;
  activeShowSeason = 1;
  activeShowEpisode = 1;
  document.getElementById("modal-kind")!.textContent = `Show · ${sh.year}`;
  document.getElementById("modal-title")!.textContent = sh.title;
  openModal();

  // Try to load season list. Falls back to S1E1 if TMDB is unreachable.
  const details = await fetchShowDetails(sh.id);

  const playUrl = (server: string) =>
    cloakUrl(
      buildShowEmbedUrl(sh.id, activeShowSeason, activeShowEpisode, server),
      sh.title,
    );

  const f = document.getElementById("modal-frame") as HTMLIFrameElement;
  f.onload = () => setLoading(false);

  const startUrl = playUrl(settings.server);
  if (settings.aboutBlank) {
    openInAboutBlank(startUrl, sh.title);
    closeModal();
    return;
  }
  f.src = startUrl;

  // Build server picker (same as movies).
  const sr = document.getElementById("server-row")!;
  sr.innerHTML = "";
  SERVERS.forEach((s) => {
    const b = document.createElement("button");
    b.className = "server-btn" + (s.id === settings.server ? " active" : "");
    b.textContent = s.label;
    b.addEventListener("click", () => {
      sr.querySelectorAll(".server-btn").forEach((el) =>
        el.classList.remove("active"),
      );
      b.classList.add("active");
      setLoading(true);
      f.src = playUrl(s.id);
    });
    sr.appendChild(b);
  });
  sr.hidden = false;

  // Build season + episode pickers.
  const ep = document.getElementById("episode-row");
  if (!ep) return;
  ep.innerHTML = "";

  if (!details || details.seasons.length === 0) {
    // Fallback when TMDB call fails: simple S/E numeric inputs.
    ep.appendChild(
      createNumberPicker("S", 1, (v) => {
        activeShowSeason = v;
        setLoading(true);
        f.src = playUrl(settings.server);
      }),
    );
    ep.appendChild(
      createNumberPicker("E", 1, (v) => {
        activeShowEpisode = v;
        setLoading(true);
        f.src = playUrl(settings.server);
      }),
    );
    ep.hidden = false;
    return;
  }

  const seasonSel = document.createElement("select");
  seasonSel.className = "ep-select";
  details.seasons.forEach((s) => {
    const o = document.createElement("option");
    o.value = String(s.season_number);
    o.textContent = `Season ${s.season_number}`;
    seasonSel.appendChild(o);
  });

  const episodeSel = document.createElement("select");
  episodeSel.className = "ep-select";

  const fillEpisodes = (seasonNum: number) => {
    const sea =
      details.seasons.find((s) => s.season_number === seasonNum) ||
      details.seasons[0];
    episodeSel.innerHTML = "";
    for (let i = 1; i <= sea.episode_count; i++) {
      const o = document.createElement("option");
      o.value = String(i);
      o.textContent = `Episode ${i}`;
      episodeSel.appendChild(o);
    }
  };
  fillEpisodes(details.seasons[0].season_number);
  activeShowSeason = details.seasons[0].season_number;
  activeShowEpisode = 1;

  seasonSel.addEventListener("change", () => {
    activeShowSeason = parseInt(seasonSel.value) || 1;
    fillEpisodes(activeShowSeason);
    activeShowEpisode = 1;
    episodeSel.value = "1";
    setLoading(true);
    f.src = playUrl(settings.server);
  });
  episodeSel.addEventListener("change", () => {
    activeShowEpisode = parseInt(episodeSel.value) || 1;
    setLoading(true);
    f.src = playUrl(settings.server);
  });

  ep.appendChild(seasonSel);
  ep.appendChild(episodeSel);
  ep.hidden = false;
}

function createNumberPicker(
  label: string,
  initial: number,
  onChange: (v: number) => void,
): HTMLElement {
  const wrap = document.createElement("label");
  wrap.className = "ep-num";
  const t = document.createElement("span");
  t.textContent = label;
  const inp = document.createElement("input");
  inp.type = "number";
  inp.min = "1";
  inp.value = String(initial);
  inp.addEventListener("change", () => {
    const v = Math.max(1, parseInt(inp.value) || 1);
    inp.value = String(v);
    onChange(v);
  });
  wrap.appendChild(t);
  wrap.appendChild(inp);
  return wrap;
}

function openInAboutBlank(url: string, title: string) {
  try {
    const win = window.open("about:blank", "_blank");
    if (!win) {
      showToast("Pop-up blocked. Allow pop-ups for this site.");
      return;
    }
    win.document.title = title;
    const html = `<!doctype html><html><head><meta charset="utf-8"><title>${escapeHtml(title)}</title><style>html,body,iframe{margin:0;padding:0;width:100%;height:100%;border:0;background:#000;overflow:hidden}</style></head><body><iframe src="${escapeAttr(url)}" allow="autoplay; fullscreen; encrypted-media; picture-in-picture; clipboard-write; gamepad" allowfullscreen referrerpolicy="no-referrer"></iframe></body></html>`;
    win.document.open();
    win.document.write(html);
    win.document.close();
  } catch {
    showToast("Couldn't open in about:blank.");
  }
}

async function goFullscreen() {
  const shell = document.querySelector(".modal-shell") as HTMLElement;
  const frame = document.getElementById("modal-frame") as HTMLIFrameElement;
  if (document.fullscreenElement) {
    try {
      await document.exitFullscreen();
    } catch {}
    return;
  }
  try {
    await (frame.requestFullscreen?.() ?? Promise.reject());
    return;
  } catch {}
  try {
    await shell?.requestFullscreen?.();
  } catch {
    showToast("Fullscreen isn't available.");
  }
}

function initModal() {
  document.querySelectorAll("[data-close]").forEach((el) => {
    el.addEventListener("click", closeModal);
  });
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape" && !document.fullscreenElement) closeModal();
  });
  document
    .getElementById("modal-fullscreen")!
    .addEventListener("click", goFullscreen);
  document.getElementById("modal-newtab")!.addEventListener("click", () => {
    const f = document.getElementById("modal-frame") as HTMLIFrameElement;
    if (!f.src || f.src === "about:blank") return;
    window.open(f.src, "_blank", "noopener");
  });
}

/* ============================================================
   Settings UI
   ============================================================ */

function applyTheme() {
  document.documentElement.dataset.theme = settings.theme;
  document.querySelectorAll<HTMLButtonElement>(".swatch").forEach((s) => {
    s.classList.toggle("active", s.dataset.theme === settings.theme);
  });
}

function applyCloak() {
  document.title = settings.cloakTitle?.trim() || "HarriUBG — Math Homework";
  const fav = document.getElementById("favicon") as HTMLLinkElement | null;
  if (!fav) return;
  if (settings.cloakIcon) {
    fav.href = settings.cloakIcon;
  } else {
    // Pull live theme colors so the favicon matches the active theme.
    const c1 = getCssVar("--accent-1") || "#22d3ee";
    const c2 = getCssVar("--accent-2") || "#a78bfa";
    fav.href =
      "data:image/svg+xml;utf8," +
      encodeURIComponent(
        `<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 64 64'><defs><linearGradient id='g' x1='0' x2='1' y1='0' y2='1'><stop offset='0' stop-color='${c1}'/><stop offset='1' stop-color='${c2}'/></linearGradient></defs><circle cx='32' cy='32' r='28' fill='url(#g)'/><path d='M22 20 L46 32 L22 44 Z' fill='#0a0a18'/></svg>`,
      );
  }
}

function bindSettings() {
  document.querySelectorAll<HTMLButtonElement>(".swatch").forEach((s) => {
    s.addEventListener("click", () => {
      settings.theme = s.dataset.theme as Settings["theme"];
      applyTheme();
      applyCloak(); // refresh favicon so it picks up the new accent colors
      saveSettings(settings);
    });
  });

  const sCloakTitle = document.getElementById(
    "set-cloak-title",
  ) as HTMLInputElement;
  const sCloakIcon = document.getElementById(
    "set-cloak-icon",
  ) as HTMLSelectElement;
  const sAboutBlank = document.getElementById(
    "set-aboutblank",
  ) as HTMLInputElement;
  const sAutoplay = document.getElementById("set-autoplay") as HTMLInputElement;
  const sServer = document.getElementById("set-server") as HTMLSelectElement;

  sCloakTitle.value = settings.cloakTitle;
  sCloakIcon.value = settings.cloakIcon;
  sAboutBlank.checked = settings.aboutBlank;
  sAutoplay.checked = settings.autoplay;
  sServer.value = settings.server;

  sCloakTitle.addEventListener("input", () => {
    settings.cloakTitle = sCloakTitle.value;
    saveSettings(settings);
    applyCloak();
  });
  sCloakIcon.addEventListener("change", () => {
    settings.cloakIcon = sCloakIcon.value;
    saveSettings(settings);
    applyCloak();
  });
  sAboutBlank.addEventListener("change", () => {
    settings.aboutBlank = sAboutBlank.checked;
    saveSettings(settings);
  });
  sAutoplay.addEventListener("change", () => {
    settings.autoplay = sAutoplay.checked;
    saveSettings(settings);
  });
  sServer.addEventListener("change", () => {
    settings.server = sServer.value;
    saveSettings(settings);
    if (activeMovie) {
      const f = document.getElementById("modal-frame") as HTMLIFrameElement;
      f.src = cloakUrl(
        buildEmbedUrl(activeMovie.id, settings.server),
        activeMovie.title,
      );
    } else if (activeShow) {
      const f = document.getElementById("modal-frame") as HTMLIFrameElement;
      f.src = cloakUrl(
        buildShowEmbedUrl(
          activeShow.id,
          activeShowSeason,
          activeShowEpisode,
          settings.server,
        ),
        activeShow.title,
      );
    }
    showToast(`Default server: ${sServer.options[sServer.selectedIndex].text}`);
  });

  document.getElementById("set-reset")!.addEventListener("click", () => {
    settings = { ...DEFAULT_SETTINGS };
    saveSettings(settings);
    sCloakTitle.value = settings.cloakTitle;
    sCloakIcon.value = settings.cloakIcon;
    sAboutBlank.checked = settings.aboutBlank;
    sAutoplay.checked = settings.autoplay;
    sServer.value = settings.server;
    applyTheme();
    applyCloak();
    showToast("Settings reset to defaults.");
  });
}

/* ============================================================
   Search
   ============================================================ */

function initSearch() {
  (
    document.getElementById("games-search") as HTMLInputElement
  ).addEventListener("input", (e) => {
    renderGames((e.target as HTMLInputElement).value);
  });
  (
    document.getElementById("movies-search") as HTMLInputElement
  ).addEventListener("input", (e) => {
    renderMovies((e.target as HTMLInputElement).value);
  });
  const showsSearch = document.getElementById(
    "shows-search",
  ) as HTMLInputElement | null;
  if (showsSearch) {
    showsSearch.addEventListener("input", (e) => {
      renderShows((e.target as HTMLInputElement).value);
    });
  }
}

/* ============================================================
   Toast
   ============================================================ */

let toastTimer = 0;
function showToast(msg: string) {
  const t = document.getElementById("toast")!;
  t.textContent = msg;
  t.hidden = false;
  window.clearTimeout(toastTimer);
  toastTimer = window.setTimeout(() => {
    t.hidden = true;
  }, 2600);
}

/* ============================================================
   Boot
   ============================================================ */

async function boot() {
  applyTheme();
  applyCloak();
  initConstellation();
  initTabs();
  initModal();
  initSearch();
  bindSettings();
  renderFeatured();
  renderGames();
  renderMovies();
  renderShows();
  renderStats();

  // Load games + movie/show posters in parallel
  await Promise.all([loadGames(), loadPosters()]);
  renderStats();
  renderFeatured();
  renderGames(
    (document.getElementById("games-search") as HTMLInputElement).value,
  );
  renderMovies(
    (document.getElementById("movies-search") as HTMLInputElement).value,
  );
  const ss = document.getElementById("shows-search") as HTMLInputElement | null;
  renderShows(ss?.value || "");
}

document.addEventListener("DOMContentLoaded", boot);
